var OikosError = class extends Error {
  static {
    __name(this, "OikosError");
  }
  code;
  details;
  constructor(message, code, details) {
    super(message);
    this.name = "OikosError";
    this.code = code;
    this.details = details;
  }
};
var ContractError = class extends OikosError {
  static {
    __name(this, "ContractError");
  }
  transactionHash;
  revertReason;
  constructor(message, code, opts) {
    super(message, code, opts?.details);
    this.name = "ContractError";
    this.transactionHash = opts?.transactionHash;
    this.revertReason = opts?.revertReason;
  }
};
var ValidationError = class extends OikosError {
  static {
    __name(this, "ValidationError");
  }
  field;
  constraint;
  constructor(message, opts) {
    super(message, "INVALID_PARAMS", opts?.details);
    this.name = "ValidationError";
    this.field = opts?.field;
    this.constraint = opts?.constraint;
  }
};
